mapper.select:
SELECT bl.id, bl.biz_type, bl.biz_code, bl.biz_item_code, bl.effect_type, bl.year, bl.month, bl.actual_year, bl.actual_month, bl.morg_code, bl.control_ehr_cd, bl.control_ehr_nm, bl.budget_org_cd, bl.budget_org_nm, bl.budget_subject_code, bl.master_project_code, bl.erp_asset_type, bl.is_internal, bl.currency, bl.amount, bl.amount_consumed_q_one, bl.amount_consumed_q_two, bl.amount_consumed_q_three, bl.amount_consumed_q_four, bl.amount_available, bl.version, bl.version_pre, bl.metadata, bl.create_time, bl.creator, bl.updater, bl.deleted, blh.operator AS operator, blh.operator_no AS operatorNo, blh.update_time AS updateTime, blh.data_source AS dataSource, blh.process_name AS processName, ehr.ehr_nm AS morgName, si.erp_acct_nm AS budgetSubjectName, pcr.prj_nm AS masterProjectName, member_view.MEMBER_NM AS erpAssetTypeName FROM budget_ledger bl LEFT JOIN budget_ledger_head blh ON bl.biz_code = blh.biz_code AND bl.biz_type = blh.biz_type AND blh.deleted = 0 AND blh.id = (SELECT MAX(id) FROM budget_ledger_head WHERE biz_code = bl.biz_code AND biz_type = bl.biz_type AND deleted = 0) LEFT JOIN ehr_org_manage_r ehr ON bl.morg_code = ehr.ehr_cd AND ehr.deleted = 0 AND ehr.year = bl.year AND ehr.id = (SELECT MAX(id) FROM ehr_org_manage_r WHERE ehr_cd = bl.morg_code AND year = bl.year AND deleted = 0) LEFT JOIN subject_info si ON bl.budget_subject_code = si.erp_acct_cd AND si.deleted = 0 AND si.year = bl.year AND si.id = (SELECT MAX(id) FROM subject_info WHERE erp_acct_cd = bl.budget_subject_code AND year = bl.year AND deleted = 0) LEFT JOIN project_control_r pcr ON bl.master_project_code = pcr.prj_cd AND pcr.deleted = 0 AND pcr.year = bl.year AND pcr.id = (SELECT MAX(id) FROM project_control_r WHERE prj_cd = bl.master_project_code AND year = bl.year AND deleted = 0) LEFT JOIN ( SELECT MEMBER_CD2, MAX(MEMBER_NM) AS MEMBER_NM FROM DATAINTEGRATION.VIEW_BUDGET_MEMBER_NAME_CODE WHERE MEMBER_CD2 IS NOT NULL GROUP BY MEMBER_CD2 ) member_view ON bl.erp_asset_type = member_view.MEMBER_CD2 AND bl.erp_asset_type != 'NAN'
LEFT JOIN budget_ledger_self_r blsr_apply ON bl.id = blsr_apply.id AND blsr_apply.biz_type = 'APPLY' AND blsr_apply.deleted = 0
LEFT JOIN budget_ledger_self_r blsr_contract ON bl.id = blsr_contract.id AND blsr_contract.biz_type = 'CONTRACT' AND blsr_contract.deleted = 0
LEFT JOIN budget_ledger_self_r blsr_apply_claim ON bl.id = blsr_apply_claim.id AND blsr_apply_claim.biz_type = 'APPLY' AND blsr_apply_claim.deleted = 0
WHERE bl.deleted = 0 AND bl.biz_type = #{params.bizType}
AND bl.id IN
#{id}
AND bl.biz_code LIKE #{bizCodePattern}
AND blh.status IN
#{statusItem}
AND bl.year IN
#{yearItem}
AND bl.month IN
#{monthItem}
AND bl.morg_code LIKE #{morgCodePattern}
AND (
bl.morg_code IN
#{ehrCd}
OR
bl.master_project_code IN
#{projectCode}
)
AND bl.budget_subject_code LIKE #{budgetSubjectCodePattern}
AND bl.erp_asset_type LIKE #{erpAssetTypePattern}
AND bl.master_project_code LIKE #{masterProjectCodePattern}
AND bl.is_internal IN
#{isInternalItem}
AND bl.effect_type IN
#{effectTypeItem}
AND ehr.ehr_nm LIKE #{morgNamePattern}
AND bl.control_ehr_cd LIKE #{controlEhrCdPattern}
AND bl.control_ehr_nm LIKE #{controlEhrNmPattern}
AND bl.budget_org_cd LIKE #{budgetOrgCdPattern}
AND bl.budget_org_nm LIKE #{budgetOrgNmPattern}
AND si.erp_acct_nm LIKE #{budgetSubjectNamePattern}
AND pcr.prj_nm LIKE #{masterProjectNamePattern}
AND member_view.MEMBER_NM LIKE #{erpAssetTypeNamePattern}
AND (blh.operator LIKE #{operatorPattern} OR blh.operator_no LIKE #{operatorPattern})
AND blsr_apply.id IS NULL
AND blsr_contract.id IS NULL
AND blsr_apply_claim.id IS NULL
ORDER BY bl.create_time DESC
